import{_ as e,o as i,c as a,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"命令队列","description":"","frontmatter":{"read_when":["更改自动回复执行或并发设置时"],"summary":"用于序列化入站自动回复运行的命令队列设计","title":"命令队列","x-i18n":{"generated_at":"2026-02-03T10:05:28Z","model":"claude-opus-4-5","provider":"pi","source_hash":"2104c24d200fb4f9620e52a19255cd614ababe19d78f3ee42936dc6d0499b73b","source_path":"concepts/queue.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/queue.md","filePath":"zh-CN/concepts/queue.md","lastUpdated":null}'),n={name:"zh-CN/concepts/queue.md"};function d(c,s,o,t,p,r){return i(),a("div",null,[...s[0]||(s[0]=[l(`<h1 id="命令队列-2026-01-16" tabindex="-1"><a class="header-anchor" href="#命令队列-2026-01-16">#</a> 命令队列（2026-01-16）</h1><p>我们通过一个小型进程内队列序列化入站自动回复运行（所有渠道），以防止多个智能体运行发生冲突，同时仍允许跨会话的安全并行。</p><h2 id="为什么需要" tabindex="-1"><a class="header-anchor" href="#为什么需要">#</a> 为什么需要</h2><ul><li>自动回复运行可能开销很大（LLM 调用），当多条入站消息接近同时到达时可能发生冲突。</li><li>序列化可以避免竞争共享资源（会话文件、日志、CLI stdin），并降低上游速率限制的可能性。</li></ul><h2 id="工作原理" tabindex="-1"><a class="header-anchor" href="#工作原理">#</a> 工作原理</h2><ul><li>一个支持通道感知的 FIFO 队列以可配置的并发上限排空每个通道（未配置的通道默认为 1；main 默认为 4，subagent 为 8）。</li><li><code>runEmbeddedPiAgent</code> 按<strong>会话键</strong>入队（通道 <code>session:&lt;key&gt;</code>），以保证每个会话只有一个活动运行。</li><li>然后每个会话运行被排入<strong>全局通道</strong>（默认为 <code>main</code>），因此整体并行度受 <code>agents.defaults.maxConcurrent</code> 限制。</li><li>启用详细日志时，如果排队运行在开始前等待超过约 2 秒，会发出简短通知。</li><li>输入指示器仍在入队时立即触发（当渠道支持时），因此在等待轮次时用户体验不受影响。</li></ul><h2 id="队列模式-按渠道" tabindex="-1"><a class="header-anchor" href="#队列模式-按渠道">#</a> 队列模式（按渠道）</h2><p>入站消息可以引导当前运行、等待后续轮次，或两者兼顾：</p><ul><li><code>steer</code>：立即注入当前运行（在下一个工具边界后取消待处理的工具调用）。如果未在流式传输，则回退到 followup。</li><li><code>followup</code>：在当前运行结束后为下一个智能体轮次入队。</li><li><code>collect</code>：将所有排队消息合并为<strong>单个</strong>后续轮次（默认）。如果消息针对不同的渠道/线程，它们会单独排空以保留路由。</li><li><code>steer-backlog</code>（又名 <code>steer+backlog</code>）：现在引导<strong>并</strong>保留消息用于后续轮次。</li><li><code>interrupt</code>（旧版）：中止该会话的活动运行，然后运行最新消息。</li><li><code>queue</code>（旧版别名）：与 <code>steer</code> 相同。</li></ul><p>steer-backlog 意味着你可以在被引导的运行之后获得后续响应，因此流式传输界面可能看起来像重复。如果你希望每条入站消息只有一个响应，请优先使用 <code>collect</code>/<code>steer</code>。 发送 <code>/queue collect</code> 作为独立命令（按会话）或设置 <code>messages.queue.byChannel.discord: &quot;collect&quot;</code>。</p><p>默认值（配置中未设置时）：</p><ul><li>所有界面 → <code>collect</code></li></ul><p>通过 <code>messages.queue</code> 全局或按渠道配置：</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  messages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    queue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;collect&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      debounceMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      cap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      drop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;summarize&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      byChannel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;collect&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="队列选项" tabindex="-1"><a class="header-anchor" href="#队列选项">#</a> 队列选项</h2><p>选项适用于 <code>followup</code>、<code>collect</code> 和 <code>steer-backlog</code>（以及当 <code>steer</code> 回退到 followup 时）：</p><ul><li><code>debounceMs</code>：在开始后续轮次前等待静默（防止&quot;继续，继续&quot;）。</li><li><code>cap</code>：每个会话的最大排队消息数。</li><li><code>drop</code>：溢出策略（<code>old</code>、<code>new</code>、<code>summarize</code>）。</li></ul><p>summarize 保留被丢弃消息的简短要点列表，并将其作为合成的后续提示注入。 默认值：<code>debounceMs: 1000</code>、<code>cap: 20</code>、<code>drop: summarize</code>。</p><h2 id="按会话覆盖" tabindex="-1"><a class="header-anchor" href="#按会话覆盖">#</a> 按会话覆盖</h2><ul><li>发送 <code>/queue &lt;mode&gt;</code> 作为独立命令，为当前会话存储该模式。</li><li>选项可以组合：<code>/queue collect debounce:2s cap:25 drop:summarize</code></li><li><code>/queue default</code> 或 <code>/queue reset</code> 清除会话覆盖。</li></ul><h2 id="范围和保证" tabindex="-1"><a class="header-anchor" href="#范围和保证">#</a> 范围和保证</h2><ul><li>适用于所有使用 Gateway 网关回复管道的入站渠道的自动回复智能体运行（WhatsApp 网页版、Telegram、Slack、Discord、Signal、iMessage、网页聊天等）。</li><li>默认通道（<code>main</code>）对入站 + 主心跳是进程范围的；设置 <code>agents.defaults.maxConcurrent</code> 以允许多个会话并行。</li><li>可能存在额外的通道（例如 <code>cron</code>、<code>subagent</code>），以便后台任务可以并行运行而不阻塞入站回复。</li><li>按会话通道保证一次只有一个智能体运行触及给定会话。</li><li>无外部依赖或后台工作线程；纯 TypeScript + promises。</li></ul><h2 id="故障排除" tabindex="-1"><a class="header-anchor" href="#故障排除">#</a> 故障排除</h2><ul><li>如果命令似乎卡住，启用详细日志并查找&quot;queued for …ms&quot;行以确认队列正在排空。</li><li>如果你需要查看队列深度，启用详细日志并观察队列计时行。</li></ul>`,24)])])}const k=e(n,[["render",d]]);export{u as __pageData,k as default};
